// Extrair dados do pedido de agendamento
// Pode vir do fluxo principal ou direto do webhook
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;

const whatsapp = data.whatsapp || data.key?.remoteJid?.replace('@s.whatsapp.net', '') || '';
const leadId = data.leadId || null;
const nome = data.nome || data.pushName || '';
const mensagem = data.mensagem || data.message?.conversation || '';

// Detectar preferência de horário na mensagem
let preferencia = 'qualquer';
const msgLower = mensagem.toLowerCase();
if (msgLower.includes('manhã') || msgLower.includes('manha')) preferencia = 'manha';
else if (msgLower.includes('tarde')) preferencia = 'tarde';
else if (msgLower.includes('noite')) preferencia = 'noite';

// Detectar dia preferido
let diaPreferido = null;
const dias = ['segunda', 'terça', 'terca', 'quarta', 'quinta', 'sexta'];
for (const dia of dias) {
  if (msgLower.includes(dia)) {
    diaPreferido = dia;
    break;
  }
}
if (msgLower.includes('amanhã') || msgLower.includes('amanha')) diaPreferido = 'amanha';
if (msgLower.includes('hoje')) diaPreferido = 'hoje';

return [{
  json: {
    whatsapp,
    leadId,
    nome,
    mensagem,
    preferencia,
    diaPreferido
  }
}];

// Calcular horários disponíveis nos próximos 5 dias úteis
const eventosExistentes = $('Google Calendar - Eventos').all().map(i => i.json);
const dadosLead = $('Extrair Dados Agendamento').first().json;
const leadInfo = $('Buscar Lead').first().json;

// Horários de trabalho: 9h-12h e 14h-18h (intervalos de 1h)
const horariosTrabalho = [
  { hora: 9, label: '09:00' },
  { hora: 10, label: '10:00' },
  { hora: 11, label: '11:00' },
  { hora: 14, label: '14:00' },
  { hora: 15, label: '15:00' },
  { hora: 16, label: '16:00' },
  { hora: 17, label: '17:00' }
];

// Mapear eventos ocupados
const eventosOcupados = eventosExistentes
  .filter(e => e.start && e.start.dateTime)
  .map(e => ({
    inicio: new Date(e.start.dateTime),
    fim: new Date(e.end.dateTime)
  }));

// Gerar próximos 5 dias úteis
const diasDisponiveis = [];
const hoje = new Date();
let diasAdicionados = 0;
let diaAtual = new Date(hoje);

// Se já passou das 17h, começar amanhã
if (hoje.getHours() >= 17) {
  diaAtual.setDate(diaAtual.getDate() + 1);
}

while (diasAdicionados < 5) {
  const diaSemana = diaAtual.getDay();
  // Pular sábado (6) e domingo (0)
  if (diaSemana !== 0 && diaSemana !== 6) {
    const nomeDia = ['Domingo', 'Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado'][diaSemana];
    const dataFormatada = diaAtual.toLocaleDateString('pt-BR');

    const horariosLivres = [];
    for (const h of horariosTrabalho) {
      // Se é hoje, pular horários já passados
      if (diaAtual.toDateString() === hoje.toDateString() && h.hora <= hoje.getHours()) continue;

      // Filtrar por preferência
      if (dadosLead.preferencia === 'manha' && h.hora >= 12) continue;
      if (dadosLead.preferencia === 'tarde' && h.hora < 14) continue;

      // Verificar se não conflita com evento existente
      const slotInicio = new Date(diaAtual);
      slotInicio.setHours(h.hora, 0, 0, 0);
      const slotFim = new Date(slotInicio);
      slotFim.setHours(h.hora + 1, 0, 0, 0);

      const conflito = eventosOcupados.some(e => 
        (slotInicio >= e.inicio && slotInicio < e.fim) ||
        (slotFim > e.inicio && slotFim <= e.fim)
      );

      if (!conflito) {
        horariosLivres.push(h.label);
      }
    }

    if (horariosLivres.length > 0) {
      diasDisponiveis.push({
        data: new Date(diaAtual).toISOString().split('T')[0],
        nomeDia,
        dataFormatada,
        horarios: horariosLivres
      });
    }
    diasAdicionados++;
  }
  diaAtual.setDate(diaAtual.getDate() + 1);
}

// Montar mensagem com horários
let msgHorarios = `Oi ${dadosLead.nome || leadInfo.nome || 'amigo(a)'}! 😊 Ótimo que quer agendar!\n\nAqui estão nossos horários disponíveis:\n\n`;

diasDisponiveis.forEach(dia => {
  msgHorarios += `📅 *${dia.nomeDia} - ${dia.dataFormatada}*\n`;
  dia.horarios.forEach(h => {
    msgHorarios += `   ⏰ ${h}\n`;
  });
  msgHorarios += '\n';
});

msgHorarios += `Escolha o melhor dia e horário para você e me avise! A reunião dura cerca de 15-30 minutinhos. 🚀`;

return [{
  json: {
    ...dadosLead,
    leadId: leadInfo.id || dadosLead.leadId,
    leadNome: leadInfo.nome || dadosLead.nome,
    diasDisponiveis,
    msgHorarios
  }
}];

// Processar confirmação de horário
const body = $input.first().json.body || $input.first().json;
const data = body.data || body;

const whatsapp = data.whatsapp || '';
const leadId = data.leadId || null;
const nome = data.nome || '';
const dataReuniao = data.dataReuniao || ''; // formato: YYYY-MM-DD
const horaReuniao = data.horaReuniao || ''; // formato: HH:MM

// Gerar link do Google Meet
const meetId = 'buildesign-' + Math.random().toString(36).substring(2, 10);

return [{
  json: {
    whatsapp,
    leadId,
    nome,
    dataReuniao,
    horaReuniao,
    meetId,
    dataHoraInicio: `${dataReuniao}T${horaReuniao}:00`,
    dataHoraFim: `${dataReuniao}T${String(parseInt(horaReuniao.split(':')[0]) + 1).padStart(2, '0')}:${horaReuniao.split(':')[1]}:00`
  }
}];

// Extrair link do Meet do evento criado
const evento = $input.first().json;
const dadosReuniao = $('Processar Confirmação').first().json;

const linkMeet = evento.hangoutLink || evento.conferenceData?.entryPoints?.[0]?.uri || 'Link será enviado por email';
const eventId = evento.id || '';

// Formatar data e hora para exibição
const dataObj = new Date(dadosReuniao.dataHoraInicio);
const dataFormatada = dataObj.toLocaleDateString('pt-BR', { weekday: 'long', day: '2-digit', month: '2-digit', year: 'numeric' });
const horaFormatada = dadosReuniao.horaReuniao;

return [{
  json: {
    ...dadosReuniao,
    linkMeet,
    eventId,
    dataFormatada,
    horaFormatada
  }
}];
